class Solution {
    public int countNumbers(String l, String r, int b) {
        long res = 0;
        for (int len = l.length(); len <= r.length(); len++) {
            long start = Long.parseLong(l, b);
            long end = Long.parseLong(r, b);
            long cur = start;
            while (cur <= end) {
                String str = Long.toString(cur, b);
                boolean flag = true;
                for (int i = 0; i < str.length() - 1; i++) {
                    if (str.charAt(i) > str.charAt(i + 1)) {
                        flag = false;
                        break;
                    }
                }
                if (flag) res = (res + 1) % 1000000007;
                cur++;
            }
        }
        return (int) res;
    }
}
